 1	import { Button } from '@patternfly/react-core';
 2	import React from 'react';
 3	import './toggle-button.css';
 4	
 5	export interface ToggleButtonProps {
 6	  isToggled: boolean;
 7	  isDisabled?: boolean;
 8	  onToggle?: (isToggled: boolean) => void;
 9	  toggledIcon?: React.ReactElement;
10	  untoggledIcon?: React.ReactElement;
11	  toggledText: string;
12	  untoggledText: string;
13	  'data-test'?: string;
14	}
15	
16	export const ToggleButton: React.FC<ToggleButtonProps> = ({
17	  isToggled,
18	  toggledIcon,
19	  untoggledIcon,
20	  onToggle,
21	  toggledText,
22	  untoggledText,
23	  isDisabled,
24	  'data-test': dataTest,
25	}) => {
26	  const icon = isToggled ? toggledIcon : untoggledIcon;
27	  const text = isToggled ? toggledText : untoggledText;
28	
29	  const handleToggle = () => {
30	    onToggle?.(!isToggled);
31	  };
32	
33	  return (
34	    <Button
35	      type="button"
36	      className="lv-plugin__toggle-button"
37	      onClick={handleToggle}
38	      variant="link"
39	      data-test={dataTest}
40	      isDisabled={isDisabled}
41	    >
42	      {icon ?? null} {text}
43	    </Button>
44	  );
45	};

